optimized_federated_query:
# Smart Federated Query with Class Constraints
# Note: Multiple class interpretations exist but all route to same endpoints
# A single query retrieves all data regardless of class ambiguity

SELECT ?chebiDrug ?chebiImage ?drug ?drugBankName ?keggDrug ?keggUrl
WHERE {

  SERVICE <http://localhost:8890/sparql/> {
    ?chebiDrug <http://purl.org/dc/elements/1.1/title> ?drugBankName . # ?chebiDrug:Compound, ?drugBankName:Literal
    ?chebiDrug <http://bio2rdf.org/ns/bio2rdf#image> ?chebiImage . # ?chebiDrug:Compound, ?chebiImage:Literal
  }

  SERVICE <http://localhost:8892/sparql/> {
    ?drug <http://www4.wiwiss.fu-berlin.de/drugbank/resource/drugbank/genericName> ?drugBankName . # ?drug:drugs, ?drugBankName:Literal
    ?drug <http://www.w3.org/1999/02/22-rdf-syntax-ns#type> <http://www4.wiwiss.fu-berlin.de/drugbank/resource/drugbank/drugs> .
    ?drug <http://www4.wiwiss.fu-berlin.de/drugbank/resource/drugbank/keggCompoundId> ?keggDrug .
  }

  SERVICE <http://localhost:8895/sparql/> {
    ?keggDrug <http://bio2rdf.org/ns/bio2rdf#url> ?keggUrl . # ?keggDrug:Enzyme, ?keggUrl:Literal
  }
}
LIMIT 1000
